class _GatherFromLastDim(torch.autograd.Function):
    """all_gather the per-rank tensor and concatenate along the last dim.

    Backward returns only this rank's contiguous slice of the incoming
    gradient (no cross-rank reduction), which is the correct conjugate of a
    concatenating gather.
    """

    @staticmethod
    def forward(ctx, input_):
        world_size = dist.get_world_size()
        ctx.world_size = world_size
        ctx.rank = dist.get_rank()
        gathered = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(gathered, input_.contiguous())
        return torch.cat(gathered, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        chunks = grad_output.chunk(ctx.world_size, dim=-1)
        return chunks[ctx.rank].contiguous()


